INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('建筑专业', '教室采光系数不达标', '学校', '普通教室采光系数1.5%，不满足中小学教室顶部采光系数不低于2.0%的要求', 'GB 50099-2011 9.1.2，普通教室采光系数不应低于2.0%');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('建筑专业', '应急照明照度不足', '学校', '教学楼内消防应急照明灯具照度0.8lx，低于疏散走道最低1.0lx的要求', 'GB 51309-2018 2.5，疏散走道地面最低水平照度不应低于1.0lx');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('建筑专业', '未设置机械排风系统', '学校', '教学楼内化学实验室未设置独立的机械排风系统', 'GB 50099-2011 10.3.4，化学实验室应设置独立的机械排风系统');
