INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('建筑专业', '防护栏杆高度不足', '学校', '小学教学楼二层及以上外廊防护栏杆高度0.95m，低于1.10m的强制要求', 'GB 55031-2022 6.2.3，临空处防护栏杆高度不应小于1.10m');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('建筑专业', '未设置封闭楼梯间', '学校', '教学楼四层及以上仅设敞开楼梯，未按要求设置封闭楼梯间', 'GB 50099-2011 8.2.1，四层及以上中小学教学楼应设封闭楼梯间');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('建筑专业', '疏散走道宽度不达标', '学校', '教学楼内主要疏散走道净宽1.1m，不满足中小学最小净宽1.4m的要求', 'GB 50099-2011 8.2.3，中小学教学楼疏散走道最小净宽不应小于1.40m');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('建筑专业', '防火分区面积超限', '学校', '高层综合教学楼建筑防火分区面积1700㎡，超出高层建筑1500㎡的上限', 'GB 50016-2014 (2018) 5.3.4，高层建筑防火分区最大允许建筑面积为1500㎡');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('建筑专业', '防护栏杆高度不足', '学校', '教学楼三层连廊及天井周边防护栏杆高度0.90m，低于1.10m的规范限值', 'GB 55031-2022 6.2.3，临空处防护栏杆高度不应小于1.10m');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('建筑专业', '疏散门开启方向反向', '学校', '教学楼地下车库与主楼连通处疏散门向内开启，不符合疏散门向外开启的强制性要求', 'GB 55037-2022 6.4.11，疏散门应向疏散方向开启');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('建筑专业', '未设置封闭楼梯间', '学校', '小学教学楼四层及以上仅设敞开楼梯间，未设置封闭楼梯间', 'GB 50099-2011 8.2.1，四层及以上中小学教学楼应设封闭楼梯间');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('建筑专业', '防火分区面积超限', '学校', '高层教学楼一至三层组合防火分区面积1850㎡，超过高层建筑1500㎡的限值', 'GB 50016-2014 (2018) 5.3.4，高层建筑防火分区最大允许建筑面积为1500㎡');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('建筑专业', '防护栏杆高度不足', '学校', '幼儿园二层室外活动平台防护栏杆高度0.85m，远低于1.10m的强制要求', 'GB 55031-2022 6.2.3，临空处防护栏杆高度不应小于1.10m');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('建筑专业', '疏散门净宽不达标', '学校', '教学楼一层通向室外的疏散门净宽1.2m，低于中小学疏散门最小净宽1.4m的规定', 'GB 50099-2011 8.2.4，中小学疏散门最小净宽不应小于1.40m');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('结构专业', '高层剪力墙加强区竖向分布筋配筋率不达标', '住宅', '高层剪力墙底部加强区竖向分布筋配筋率仅 0.20%，不满足抗震最小配筋要求', 'GB 50010-2010 (2015 版) 11.7.17，7 度抗震剪力墙底部加强区最小配筋率 0.30%');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('结构专业', '未设置抗震伸缩后浇带', '住宅', '主楼与地下车库相连位置未设置抗震伸缩后浇带，未考虑不均匀沉降', 'GB 50011-2010 (2016 版) 3.4.10，主楼与裙 / 车库交界应设沉降后浇带');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('结构专业', '高层连梁未配置交叉暗撑', '住宅', '高层连梁跨高比小于 2.5，未按要求配置交叉暗撑', 'GB 50010-2010 (2015 版) 11.7.11，跨高比≤2.5 连梁宜设交叉钢筋暗撑');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('结构专业', '顶部未配套构造拉结筋', '住宅', '洋房砌体填充墙顶部未设置斜砌顶紧，未配套构造拉结筋', 'GB 50003-2011 6.3.4，填充墙顶部斜砌、全长贯通拉结筋');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('结构专业', '楼梯平台梁未设置混凝土构造柱承托', '住宅', '多层洋房楼梯平台梁支承在填充墙上，未设置混凝土构造柱承托', 'GB 50011-2010 (2016 版) 13.3.4，梁下墙体应增设构造柱');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('结构专业', '屋面悬挑阳台根部未设置抗扭附加钢筋', '住宅', '屋面悬挑阳台根部未设置抗扭附加钢筋，未满足倾覆验算配筋', 'GB 50009-2012 5.5.1，悬挑构件根部增设抗扭附加筋');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('结构专业', '住宅分户楼板最小厚度不足 ', '住宅', '保障房楼板厚度仅 90mm，住宅分户楼板最小厚度不足 100mm', 'GB 50010-2010 (2015 版) 3.6.3，住宅分户楼板厚度不宜小于 100mm');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('结构专业', '楼梯间四角未设置抗震构造柱', '住宅', '楼梯间四角未设置抗震构造柱，不满足多层砌体抗震构造要求', 'GB 50011-2010 (2016 版) 7.3.1，楼梯四角必须设置构造柱');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('结构专业', '外墙门窗洞口两侧未设置 墙体拉结筋', '住宅', '外墙门窗洞口两侧未设置长度≥1000mm 墙体拉结筋', 'GB 50011-2010 (2016 版) 13.3.2，洞口两侧拉结筋伸入墙体≥1000mm');
INSERT INTO history_issues (major, issue_summary, building_type, issue_description, requirement) VALUES ('结构专业', '高层框架柱箍筋加密区长度小于柱高限值', '住宅', '高层框架柱箍筋加密区长度仅 500mm，小于规范 1.5 倍柱高限值', 'GB 50011-2010 (2016 版) 6.3.7，柱端加密区长度取柱长边、1/6 柱高二者大值');
